return $input.all()
  .filter(item => String(item.json['Key'] ?? '').trim() !== '')
  .map(item => {
    const j = item.json;
    return { json: {
      key: j['Key'],
      reporter: String(j['Reporter'] ?? '').trim(),
      businessUnit: String(j['Business Unit'] ?? '').trim(),
      hours: Number(j['Time Spent (Hours)'] ?? 0)
    } };
  });

const items = $input.all();
const seen = new Map();
items.forEach((item, idx) => {
  const reporter = String(item.json['Reporter'] ?? '').trim();
  if (reporter && !seen.has(reporter)) seen.set(reporter, idx);
});
return Array.from(seen.entries()).map(([reporter, idx]) => ({
  json: { reporterValue: reporter, isEmail: reporter.includes('@') },
  pairedItem: idx
}));

const items = $input.all();
const groups = new Map();
items.forEach((item, idx) => {
  const key = (item.pairedItem && typeof item.pairedItem.item === 'number') ? item.pairedItem.item : idx;
  if (!groups.has(key)) groups.set(key, []);
  groups.get(key).push({ json: item.json, idx });
});
const output = [];
for (const group of groups.values()) {
  const rep = $('List Unique Reporters').itemMatching(group[0].idx).json;
  const valid = group.map(g => g.json).filter(j => j && j.dn);
  let result;
  if (valid.length === 0) {
    result = { reporterValue: rep.reporterValue, isEmail: rep.isEmail, status: 'needsTier3' };
  } else if (valid.length === 1) {
    result = { reporterValue: rep.reporterValue, isEmail: rep.isEmail, status: 'resolved', company: valid[0].company || null, matchType: 'exact', flag: null };
  } else {
    result = { reporterValue: rep.reporterValue, isEmail: rep.isEmail, status: 'ambiguous', candidates: valid, matchType: 'ambiguous_exact' };
  }
  output.push({ json: result, pairedItem: group[0].idx });
}
return output;

const items = $input.all();
const groups = new Map();
items.forEach((item, idx) => {
  const key = (item.pairedItem && typeof item.pairedItem.item === 'number') ? item.pairedItem.item : idx;
  if (!groups.has(key)) groups.set(key, []);
  groups.get(key).push({ json: item.json, idx });
});
const output = [];
for (const group of groups.values()) {
  const rep = $('List Unique Reporters').itemMatching(group[0].idx).json;
  const valid = group.map(g => g.json).filter(j => j && j.dn);
  let result;
  if (valid.length === 0) {
    result = { reporterValue: rep.reporterValue, isEmail: rep.isEmail, status: 'final', company: null, matchType: 'no_match', flag: 'AD lookup failed - no match found (exact or wildcard). Used spreadsheet Business Unit value.' };
  } else if (valid.length === 1) {
    result = { reporterValue: rep.reporterValue, isEmail: rep.isEmail, status: 'final', company: valid[0].company || null, matchType: 'fuzzy', flag: 'Fuzzy AD match on wildcard name search - verify.' };
  } else {
    result = { reporterValue: rep.reporterValue, isEmail: rep.isEmail, status: 'ambiguous', candidates: valid, matchType: 'ambiguous_wildcard' };
  }
  output.push({ json: result, pairedItem: group[0].idx });
}
return output;

const lookupMap = {};
const flags = [];
for (const item of $input.all()) {
  const j = item.json;
  lookupMap[j.reporterValue] = { company: j.company || null, matchType: j.matchType, flag: j.flag || null };
  if (j.matchType && j.matchType !== 'exact') flags.push({ reporter: j.reporterValue, matchType: j.matchType, flag: j.flag });
}
return [{ json: { lookupMap, flags } }];

const lineItems = $json.lineItems || $json.output?.lineItems || [];
const relevant = lineItems.filter(li => Math.abs(Number(li.currentAmount)) > 0.001);
let needsManualReview = false, invoiceTotal = null, invoiceHours = null, note = '';
if (relevant.length !== 1) {
  needsManualReview = true;
  note = 'Expected exactly 1 non-zero line item, found ' + relevant.length + '. Manual review required - cannot auto-split.';
} else {
  invoiceTotal = Number(relevant[0].currentAmount);
  const m = String(relevant[0].description).match(/([\d.]+)\s*Hours?/i);
  invoiceHours = m ? parseFloat(m[1]) : null;
  if (invoiceHours === null) {
    needsManualReview = true;
    note = 'Could not parse hours from line item description: "' + relevant[0].description + '"';
  }
}
return [{ json: { needsManualReview, invoiceTotal, invoiceHours, note, allLineItems: lineItems } }];

const rows = $('Normalize BU Rows').all().map(i => i.json);
const lookup = $('Build Reporter Lookup').first().json.lookupMap;
const invoice = $('Validate Invoice Line Items').first().json;

const mismatches = [];
const lookupNotes = [];
const hoursByBU = {};

for (const row of rows) {
  const entry = lookup[row.reporter] || { company: null, matchType: 'no_match', flag: 'Reporter not looked up' };
  const adBU = entry.company;
  const sheetBU = row.businessUnit;
  const finalBU = adBU || sheetBU || 'UNKNOWN';

  if (adBU && sheetBU && adBU !== sheetBU) {
    mismatches.push({ key: row.key, reporter: row.reporter, spreadsheetBU: sheetBU, adBU, note: 'AD company differs from spreadsheet Business Unit - using AD value, spreadsheet not auto-corrected.' });
  }
  if (entry.matchType && entry.matchType !== 'exact') {
    lookupNotes.push({ key: row.key, reporter: row.reporter, matchType: entry.matchType, flag: entry.flag });
  }

  hoursByBU[finalBU] = (hoursByBU[finalBU] || 0) + Number(row.hours || 0);
}

const totalHours = Object.values(hoursByBU).reduce((a, b) => a + b, 0);
const sheetHoursSum = rows.reduce((a, r) => a + Number(r.hours || 0), 0);

const sanityCheck = {
  spreadsheetHoursTotal: sheetHoursSum,
  invoiceHours: invoice.invoiceHours,
  hoursMatch: invoice.invoiceHours !== null && Math.abs(sheetHoursSum - invoice.invoiceHours) < 0.01
};

let splits = [];
if (!invoice.needsManualReview && invoice.invoiceTotal !== null && totalHours > 0) {
  splits = Object.entries(hoursByBU).map(([bu, hours]) => ({
    businessUnit: bu,
    hours,
    percent: hours / totalHours,
    amount: Math.round((hours / totalHours) * invoice.invoiceTotal * 100) / 100
  }));
}

let summaryHtml;
if (invoice.needsManualReview) {
  summaryHtml = '<h2>Manual Review Needed</h2><p>' + invoice.note + '</p>';
} else {
  const sortedSplits = [...splits].sort((a, b) => a.businessUnit.localeCompare(b.businessUnit));
  const grandTotalHours = sortedSplits.reduce((a, s) => a + s.hours, 0);
  const grandTotalAmount = sortedSplits.reduce((a, s) => a + s.amount, 0);
  const splitRows = sortedSplits.map(s => '<tr><td>' + s.businessUnit + '</td><td class="hrs">' + s.hours + '</td><td>$' + s.amount.toFixed(2) + '</td></tr>').join('');
  const mismatchItems = mismatches.map(m => '<li>' + m.key + ' (' + m.reporter + '): spreadsheet says ' + m.spreadsheetBU + ', AD says ' + m.adBU + '</li>').join('');
  const noteItems = lookupNotes.map(n => '<li>' + n.key + ' (' + n.reporter + '): ' + n.flag + '</li>').join('');
  const tableStyle = '<style>' +
    'table.split-table { border-collapse:collapse; margin:0 auto; font-size:16px; }' +
    'table.split-table th, table.split-table td { padding:10px 16px; border:1px solid #ccc; }' +
    'table.split-table th { background:#eef1f5; }' +
    'table.split-table td.hrs { text-align:center; }' +
    'table.split-table tr.grand-total { background:#f5f5f5; }' +
    '</style>';
  summaryHtml = tableStyle + '<h2>MGA Help Desk Invoice Split</h2>' +
    '<table class="split-table"><tr><th>Studio</th><th>Hours</th><th>Split</th></tr>' + splitRows + '<tr class="grand-total"><td><strong>Grand Total</strong></td><td class="hrs"><strong>' + grandTotalHours + '</strong></td><td><strong>$' + grandTotalAmount.toFixed(2) + '</strong></td></tr></table>' +
    (sanityCheck.hoursMatch ? '' : '<p><strong>WARNING:</strong> spreadsheet hours (' + sanityCheck.spreadsheetHoursTotal + ') do not match invoice hours (' + sanityCheck.invoiceHours + ')</p>') +
    (mismatches.length ? '<h3>Business Unit Mismatches (AD vs spreadsheet)</h3><ul>' + mismatchItems + '</ul>' : '') +
    (lookupNotes.length ? '<h3>Lookup Notes (verify)</h3><ul>' + noteItems + '</ul>' : '');
}

return [{ json: {
  needsManualReview: invoice.needsManualReview,
  reviewNote: invoice.note,
  invoiceTotal: invoice.invoiceTotal,
  splits,
  sanityCheck,
  mismatches,
  lookupNotes,
  summaryHtml
} }];

const text = $json.text || '';
const lines = text.split(/\r?\n/).map(l => l.trim()).filter(Boolean);

const numTok = '[\\d,]+\\.\\d{2}';
const rowRe = new RegExp('^(.*?)\\s+(' + numTok + ')\\s+(' + numTok + ')\\s+(' + numTok + ')\\s+(' + numTok + ')\\s+(' + numTok + ')$');
const stopMarkers = ['Total Fee', 'SUBTOTAL', 'AMOUNT DUE', 'Outstanding Invoices'];

const lineItems = [];
for (const line of lines) {
  if (stopMarkers.some(m => line.startsWith(m))) break;
  const m = line.match(rowRe);
  if (!m) continue;
  const description = m[1].trim();
  const currentAmount = parseFloat(m[6].replace(/,/g, ''));
  lineItems.push({ description, currentAmount });
}

return [{ json: { lineItems } }];

const j = $json;
const count = Array.isArray(j.candidates) ? j.candidates.length : 0;
return {
  json: {
    reporterValue: j.reporterValue,
    isEmail: j.isEmail,
    company: null,
    matchType: 'ambiguous',
    flag: 'Ambiguous AD match (' + count + ' candidates) - manual review needed. Used spreadsheet Business Unit value.'
  }
};
